
import axios from 'axios';

const BASE_URL = 'https://pixabay.com/api/';
const API_KEY = '56048783-6f228d4081fb198149de51908';

export function getImagesByQuery(query) {
  return axios.get(BASE_URL, {
    params: {
      key: API_KEY,
      q: query,
      image_type: 'photo',
      orientation: 'horizontal',
      safesearch: true,
    },
  });
}